GRANT SELECT ON vport.profile_public_details TO authenticated, anon;

Grant table-level SELECT so PostgreSQL lets the role reach RLS evaluation.
-- Without this the client gets 42501 "permission denied" before RLS runs.
GRANT SELECT                 ON vport.content_pages TO authenticated;

GRANT SELECT on vport.rates is intentional — exchange rates are public
-- display data on VPORT profiles.
DROP POLICY IF EXISTS rates_select ON vport.rates;

grant policies above. '
