grant level — no RLS policy can re-grant
-- it at the session level, making this more robust than a policy-only approach.
REVOKE INSERT, UPDATE, DELETE ON vport.service_catalog FROM authenticated;

grant rows.
-- can_manage_domain (SECURITY DEFINER) bypasses this entirely for its check.
DROP POLICY IF EXISTS "moderators_select_own_actor" ON moderation.moderators;

